mapper.select:
select sc.*, u.true_name as uname
from t_sale_chance sc left join t_user u on sc.assign_man = u.id
where sc.is_valid = 1

    and sc.customer_name like concat('%',#{customerName},'%')


    and sc.create_man like concat('%',#{createMan},'%')


    and sc.state = #{state}


    and sc.assign_man = #{assignMan}


    and sc.dev_result = #{devResult}

order by sc.create_date desc

mapper.update:
update t_sale_chance
customer_name = #{customerName,jdbcType=VARCHAR}, chance_source = #{chanceSource,jdbcType=VARCHAR}, link_man = #{linkMan,jdbcType=VARCHAR}, link_phone = #{linkPhone,jdbcType=VARCHAR}, cgjl = #{cgjl,jdbcType=INTEGER}, overview = #{overview,jdbcType=VARCHAR}, description = #{description,jdbcType=VARCHAR}, create_man = #{createMan,jdbcType=VARCHAR}, assign_man = #{assignMan,jdbcType=INTEGER}, assign_time = #{assignTime,jdbcType=TIMESTAMP}, state = #{state,jdbcType=INTEGER}, dev_result = #{devResult,jdbcType=INTEGER}, is_valid = #{isValid,jdbcType=INTEGER},
where id = #{id,jdbcType=INTEGER}
